// Validate webhook input for v2.5 - T1 Hybrid Webhook
const input = $input.first().json;

// Extract data from webhook body structure
const webhookBody = input.body || input;
const actualInput = webhookBody.prompt_version_id ? webhookBody : input;

// Required fields validation
if (!actualInput.prompt_version_id) {
  throw new Error('Missing required field: prompt_version_id. Received: ' + JSON.stringify(input));
}

// Validate UUID format
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(actualInput.prompt_version_id)) {
  throw new Error('Invalid prompt_version_id format: must be UUID');
}

// evaluator_config_id is optional - if provided, auto-evaluation will run after battles
const evaluatorConfigId = actualInput.evaluator_config_id || null;
if (evaluatorConfigId && !uuidRegex.test(evaluatorConfigId)) {
  throw new Error('Invalid evaluator_config_id format: must be UUID');
}

// Validate mode (optional, defaults to 'single')
const validModes = ['single', 'full_cycle_with_review'];
const mode = actualInput.mode || 'single';
if (!validModes.includes(mode)) {
  throw new Error(`Invalid mode: ${mode}. Must be one of: ${validModes.join(', ')}`);
}

// Validate max_iterations (optional, defaults to 1 for single, 3 for full_cycle)
let maxIterations = actualInput.max_iterations;
if (maxIterations === undefined) {
  maxIterations = mode === 'single' ? 1 : 3;
}
if (typeof maxIterations !== 'number' || maxIterations < 1 || maxIterations > 10) {
  throw new Error('max_iterations must be a number between 1 and 10');
}

// Validate max_turns (optional, defaults to 50)
let maxTurns = actualInput.max_turns;
if (maxTurns === undefined) {
  maxTurns = 50;
}
maxTurns = Number(maxTurns);
if (isNaN(maxTurns) || maxTurns < 5 || maxTurns > 100) {
  maxTurns = 50;
}

// tool_scenario_id is VARCHAR (optional)
const toolScenarioId = actualInput.tool_scenario_id || null;

return {
  json: {
    prompt_version_id: actualInput.prompt_version_id,
    evaluator_config_id: evaluatorConfigId,
    mode: mode,
    max_iterations: maxIterations,
    max_turns: maxTurns,
    tool_scenario_id: toolScenarioId,
    validated_at: new Date().toISOString()
  }
};

